import React, { useState } from 'react';
import { AlertCircle, PlusCircle, XCircle } from 'lucide-react';

const BasicForm = () => {
  const [formData, setFormData] = useState({
    clientName: '',
    clientNumber: '',
    hearingDate: '',
    declarationStatus: '',
    notes: '',
    riders: []
  });

  const [errors, setErrors] = useState({});

  // Format A number as ###-###-###
  const formatANumber = (value) => {
    const numbers = value.replace(/[^\d]/g, '');
    if (numbers.length <= 3) return numbers;
    if (numbers.length <= 6) return `${numbers.slice(0,3)}-${numbers.slice(3)}`;
    return `${numbers.slice(0,3)}-${numbers.slice(3,6)}-${numbers.slice(6,9)}`;
  };

  // Handle A number input
  const handleANumberInput = (value, index = null) => {
    const formatted = formatANumber(value);
    if (formatted.replace(/-/g, '').length <= 9) {
      if (index !== null) {
        // Handle rider A number
        const newRiders = [...formData.riders];
        newRiders[index] = { ...newRiders[index], aNumber: formatted };
        setFormData({ ...formData, riders: newRiders });
      } else {
        // Handle client A number
        setFormData({ ...formData, clientNumber: formatted });
      }
    }
  };

  // Add new rider
  const addRider = () => {
    setFormData({
      ...formData,
      riders: [...formData.riders, { aNumber: '', isMinor: false }]
    });
  };

  // Remove rider
  const removeRider = (index) => {
    const newRiders = formData.riders.filter((_, i) => i !== index);
    setFormData({ ...formData, riders: newRiders });
  };

  // Handle rider age status change
  const handleRiderAgeChange = (index, isMinor) => {
    const newRiders = [...formData.riders];
    newRiders[index] = { ...newRiders[index], isMinor };
    setFormData({ ...formData, riders: newRiders });
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prevState => ({
      ...prevState,
      [name]: value
    }));
    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: '' }));
    }
  };

  const validateForm = () => {
    const newErrors = {};
    if (!formData.clientName.trim()) newErrors.clientName = 'Client name is required';
    if (!formData.clientNumber.trim()) newErrors.clientNumber = 'A number is required';
    if (!formData.declarationStatus) newErrors.declarationStatus = 'Declaration status is required';
    
    // Validate riders
    formData.riders.forEach((rider, index) => {
      if (!rider.aNumber) {
        newErrors[`rider${index}`] = 'Rider A number is required';
      }
    });

    return newErrors;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const newErrors = validateForm();
    
    if (Object.keys(newErrors).length === 0) {
      console.log('Form submitted:', formData);
    } else {
      setErrors(newErrors);
    }
  };

  return (
    <div className="max-w-2xl mx-auto p-6 bg-white dark:bg-gray-800 rounded-lg shadow">
      <h2 className="text-2xl font-bold mb-6 text-gray-900 dark:text-white">Client Information Form</h2>
      
      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Client Name */}
        <div>
          <label className="block text-sm font-medium text-gray-700 dark:text-gray-200 mb-1">
            Client's Name
          </label>
          <input
            type="text"
            name="clientName"
            value={formData.clientName}
            onChange={handleChange}
            className={`w-full px-3 py-2 border rounded-md ${
              errors.clientName ? 'border-red-500' : 'border-gray-300'
            } dark:border-gray-600 dark:bg-gray-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500`}
          />
          {errors.clientName && (
            <p className="mt-1 text-sm text-red-500 flex items-center">
              <AlertCircle className="h-4 w-4 mr-1" />
              {errors.clientName}
            </p>
          )}
        </div>

        {/* Client A# */}
        <div>
          <label className="block text-sm font-medium text-gray-700 dark:text-gray-200 mb-1">
            Client A#
          </label>
          <input
            type="text"
            value={formData.clientNumber}
            onChange={(e) => handleANumberInput(e.target.value)}
            placeholder="123-456-789"
            className={`w-full px-3 py-2 border rounded-md ${
              errors.clientNumber ? 'border-red-500' : 'border-gray-300'
            } dark:border-gray-600 dark:bg-gray-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500`}
          />
          {errors.clientNumber && (
            <p className="mt-1 text-sm text-red-500 flex items-center">
              <AlertCircle className="h-4 w-4 mr-1" />
              {errors.clientNumber}
            </p>
          )}
        </div>

        {/* Riders Section */}
        <div>
          <div className="flex items-center justify-between mb-2">
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-200">
              Riders
            </label>
            <button
              type="button"
              onClick={addRider}
              className="flex items-center text-blue-600 hover:text-blue-700 text-sm"
            >
              <PlusCircle className="h-4 w-4 mr-1" />
              Add Rider
            </button>
          </div>
          
          <div className="space-y-4">
            {formData.riders.map((rider, index) => (
              <div key={index} className="flex items-start space-x-4 p-4 border rounded-md">
                <div className="flex-grow">
                  <input
                    type="text"
                    value={rider.aNumber}
                    onChange={(e) => handleANumberInput(e.target.value, index)}
                    placeholder="123-456-789"
                    className="w-full px-3 py-2 border rounded-md border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                  
                  <div className="mt-2 flex items-center space-x-4">
                    <label className="inline-flex items-center">
                      <input
                        type="radio"
                        checked={!rider.isMinor}
                        onChange={() => handleRiderAgeChange(index, false)}
                        className="form-radio h-4 w-4 text-blue-600"
                      />
                      <span className="ml-2 text-sm text-gray-700 dark:text-gray-200">Over 18</span>
                    </label>
                    <label className="inline-flex items-center">
                      <input
                        type="radio"
                        checked={rider.isMinor}
                        onChange={() => handleRiderAgeChange(index, true)}
                        className="form-radio h-4 w-4 text-blue-600"
                      />
                      <span className="ml-2 text-sm text-gray-700 dark:text-gray-200">Under 18</span>
                    </label>
                  </div>
                </div>
                
                <button
                  type="button"
                  onClick={() => removeRider(index)}
                  className="text-red-500 hover:text-red-700"
                >
                  <XCircle className="h-5 w-5" />
                </button>
              </div>
            ))}
          </div>
        </div>

        {/* Hearing Date */}
        <div>
          <label className="block text-sm font-medium text-gray-700 dark:text-gray-200 mb-1">
            Hearing Date
          </label>
          <input
            type="date"
            name="hearingDate"
            value={formData.hearingDate}
            onChange={handleChange}
            className="w-full px-3 py-2 border border-gray-300 rounded-md dark:border-gray-600 dark:bg-gray-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>

        {/* Declaration Status */}
        <div>
          <label className="block text-sm font-medium text-gray-700 dark:text-gray-200 mb-1">
            Declaration Status
          </label>
          <select
            name="declarationStatus"
            value={formData.declarationStatus}
            onChange={handleChange}
            className={`w-full px-3 py-2 border rounded-md ${
              errors.declarationStatus ? 'border-red-500' : 'border-gray-300'
            } dark:border-gray-600 dark:bg-gray-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500`}
          >
            <option value="">Select Status</option>
            <option value="ready">Ready to be uploaded</option>
            <option value="uploaded">Uploaded</option>
            <option value="pending">Pending</option>
          </select>
          {errors.declarationStatus && (
            <p className="mt-1 text-sm text-red-500 flex items-center">
              <AlertCircle className="h-4 w-4 mr-1" />
              {errors.declarationStatus}
            </p>
          )}
        </div>

        {/* Notes */}
        <div>
          <label className="block text-sm font-medium text-gray-700 dark:text-gray-200 mb-1">
            Notes
          </label>
          <textarea
            name="notes"
            value={formData.notes}
            onChange={handleChange}
            rows="4"
            className="w-full px-3 py-2 border border-gray-300 rounded-md dark:border-gray-600 dark:bg-gray-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
            placeholder="Add any additional notes about the client..."
          />
        </div>

        {/* Submit Button */}
        <div>
          <button
            type="submit"
            className="w-full bg-blue-600 text-white py-2 px-4 rounded-md hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 transition-colors"
          >
            Save Client Information
          </button>
        </div>
      </form>
    </div>
  );
};

export default BasicForm;
